// Parse line directives to build line mapping
// lineMap[i] = {filename, line} for preprocessed line i+1
std::vector<LineInfo> lineMap;
std::string currentFile;
int currentLine = 1;

size_t pos = 0;
while (pos < rawContent.length()) {
  // Find end of current line
  size_t lineEnd = rawContent.find('\n', pos);
  if (lineEnd == std::string::npos) {
    lineEnd = rawContent.length();
  }
  std::string line = rawContent.substr(pos, lineEnd - pos);
  // Remove trailing \r
  if (!line.empty() && line.back() == '\r') {
    line.pop_back();
  }

  // Check if this is a line directive
  std::regex re(R"xx(^\s*#\s*(\d+)\s+"([^"]*)".*)xx", std::regex::ECMAScript);
  std::smatch match;
  if (std::regex_match(line, match, re)) {
    currentLine = std::stoi(match[1].str());
    currentFile = match[2].str();
  }

  lineMap.push_back({currentFile, currentLine});
  currentLine++;
  pos = lineEnd + 1;
}

